module register_8bit_with_enable(CLK, RESET, EN, D, Q);
input CLK, RESET, EN;
input [7:0] D;
output [7:0] Q;
reg [7:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RESET or posedge dbg_halt) begin
    if (RESET)
        Q <= 8'b00000000;
    else if (EN)
        Q <= D;
end

endmodule
